### Create and Use Configurable NestJS Dynamic Modules

Source: https://context7.com/nestjs/nest/llms.txt

This code defines a NestJS `DatabaseModule` as a dynamic module, allowing for configurable database connections. It provides `forRoot` for direct, synchronous configuration and `forRootAsync` for asynchronous configuration using a factory function and dependency injection, commonly used for fetching configurations from a `ConfigService`. The module exports a 'DATABASE_CONNECTION' provider and is marked as global. Examples demonstrate how to import and configure this dynamic module within an `AppModule` using both synchronous and asynchronous approaches.

```typescript
import { Module, DynamicModule, Provider } from '@nestjs/common';

export interface DatabaseOptions {
  host: string;
  port: number;
  username: string;
  password: string;
  database: string;
}

@Module({})
export class DatabaseModule {
  static forRoot(options: DatabaseOptions): DynamicModule {
    const connectionProvider: Provider = {
      provide: 'DATABASE_CONNECTION',
      useFactory: async () => {
        // Create database connection
        const connection = await createConnection(options);
        return connection;
      },
    };

    return {
      module: DatabaseModule,
      providers: [connectionProvider],
      exports: [connectionProvider],
      global: true,
    };
  }

  static forRootAsync(options: {
    useFactory: (...args: any[]) => Promise<DatabaseOptions> | DatabaseOptions;
    inject?: any[];
  }): DynamicModule {
    const connectionProvider: Provider = {
      provide: 'DATABASE_CONNECTION',
      useFactory: async (...args: any[]) => {
        const config = await options.useFactory(...args);
        return createConnection(config);
      },
      inject: options.inject || [],
    };

    return {
      module: DatabaseModule,
      providers: [connectionProvider],
      exports: [connectionProvider],
      global: true,
    };
  }
}

// Usage
@Module({
  imports: [
    DatabaseModule.forRoot({
      host: 'localhost',
      port: 5432,
      username: 'user',
      password: 'pass',
      database: 'mydb',
    }),
  ],
})
export class AppModule {}

// Async configuration
@Module({
  imports: [
    DatabaseModule.forRootAsync({
      useFactory: (configService: ConfigService) => ({
        host: configService.get('DB_HOST'),
        port: configService.get('DB_PORT'),
        username: configService.get('DB_USER'),
        password: configService.get('DB_PASS'),
        database: configService.get('DB_NAME'),
      }),
      inject: [ConfigService],
    }),
  ],
})
export class AppModule {}
```

