### Implement Microservice Client with ClientProxy

Source: https://context7.com/nestjs/nest/llms.txt

Creates an injectable service that communicates with microservices using ClientProxy. The service sends synchronous requests via the send() method and asynchronous events via emit(). It requires injection of a ClientProxy instance configured with the microservice transport details.

```typescript
import { Injectable, Inject } from '@nestjs/common';
import { ClientProxy } from '@nestjs/microservices';

@Injectable()
export class AppService {
  constructor(@Inject('MATH_SERVICE') private client: ClientProxy) {}

  async accumulate(data: number[]) {
    return this.client.send({ cmd: 'sum' }, data).toPromise();
  }

  emitUserCreated(user: any) {
    this.client.emit('user_created', user);
  }
}
```

