### Perform End-to-End Testing on a NestJS Application

Source: https://context7.com/nestjs/nest/llms.txt

This snippet shows how to conduct end-to-end (E2E) tests for a NestJS application using `supertest`. It initializes the entire application, sends HTTP requests to API endpoints like `/cats` (GET) and `/cats` (POST), and asserts on the HTTP status codes and response bodies. This tests the complete request-response lifecycle from HTTP request to database interaction (if configured).

```typescript
import * as request from 'supertest';
import { Test } from '@nestjs/testing';
import { INestApplication } from '@nestjs/common';
import { AppModule } from '../src/app.module';

describe('Cats (e2e)', () => {
  let app: INestApplication;

  beforeAll(async () => {
    const moduleFixture = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    await app.init();
  });

  afterAll(async () => {
    await app.close();
  });

  it('/cats (GET)', () => {
    return request(app.getHttpServer())
      .get('/cats')
      .expect(200)
      .expect(res => {
        expect(res.body).toHaveProperty('items');
        expect(Array.isArray(res.body.items)).toBe(true);
      });
  });

  it('/cats (POST)', () => {
    return request(app.getHttpServer())
      .post('/cats')
      .send({ name: 'Test Cat', age: 3, breed: 'Persian' })
      .expect(201)
      .expect(res => {
        expect(res.body).toHaveProperty('id');
        expect(res.body.name).toBe('Test Cat');
      });
  });
});
```

