### Implement NestJS Controller with HTTP Routing and Decorators (TypeScript)

Source: https://context7.com/nestjs/nest/llms.txt

This code defines a `CatsController` that handles various HTTP requests (GET, POST, PUT, DELETE) for a 'cats' resource. It extensively uses NestJS decorators like `@Controller`, `@Get`, `@Post`, `@Param`, `@Body`, `@Query`, `@HttpCode`, `@UseGuards`, and `@UseInterceptors` to define routes, extract request data, set HTTP status, and apply cross-cutting concerns such as authentication and response transformation. It also demonstrates dependency injection for `CatsService` and input validation with `ParseIntPipe`.

```typescript
import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Param,
  Body,
  Query,
  HttpCode,
  HttpStatus,
  ParseIntPipe,
  UseGuards,
  UseInterceptors,
} from '@nestjs/common';
import { CatsService } from './cats.service';
import { CreateCatDto, UpdateCatDto, QueryDto } from './dto';
import { AuthGuard } from '../auth/auth.guard';
import { TransformInterceptor } from '../common/interceptors/transform.interceptor';

@Controller('cats')
@UseGuards(AuthGuard)
@UseInterceptors(TransformInterceptor)
export class CatsController {
  constructor(private readonly catsService: CatsService) {}

  @Get()
  async findAll(@Query() query: QueryDto) {
    const { page = 1, limit = 10 } = query;
    return this.catsService.findAll({ page, limit });
  }

  @Get(':id')
  async findOne(@Param('id', ParseIntPipe) id: number) {
    const cat = await this.catsService.findOne(id);
    if (!cat) {
      throw new NotFoundException(`Cat with ID ${id} not found`);
    }
    return cat;
  }

  @Post()
  @HttpCode(HttpStatus.CREATED)
  async create(@Body() createCatDto: CreateCatDto) {
    return this.catsService.create(createCatDto);
  }

  @Put(':id')
  async update(
    @Param('id', ParseIntPipe) id: number,
    @Body() updateCatDto: UpdateCatDto,
  ) {
    return this.catsService.update(id, updateCatDto);
  }

  @Delete(':id')
  @HttpCode(HttpStatus.NO_CONTENT)
  async remove(@Param('id', ParseIntPipe) id: number) {
    await this.catsService.remove(id);
  }
}
```

