### Implement Injectable Service with Dependency Injection in NestJS

Source: https://context7.com/nestjs/nest/llms.txt

This snippet demonstrates how to create a `CatsService` in NestJS, showcasing dependency injection for repositories, logging, and optional configuration. It includes methods for common CRUD operations (findAll, findOne, create, update, remove) on a `Cat` entity, handling pagination, error logging, and throwing a `NotFoundException`.

```typescript
import { Injectable, Inject, Optional, Scope } from '@nestjs/common';
import { CreateCatDto, UpdateCatDto } from './dto';

@Injectable({ scope: Scope.DEFAULT })
export class CatsService {
  constructor(
    @Inject('CATS_REPOSITORY') private readonly catsRepo: Repository<Cat>,
    private readonly logger: LoggerService,
    @Optional() @Inject('CONFIG') private config?: ConfigService,
  ) {}

  async findAll(options: { page: number; limit: number }) {
    const { page, limit } = options;
    const [items, total] = await this.catsRepo.findAndCount({
      skip: (page - 1) * limit,
      take: limit,
    });

    return {
      items,
      total,
      page,
      pages: Math.ceil(total / limit),
    };
  }

  async findOne(id: number): Promise<Cat> {
    try {
      return await this.catsRepo.findOneOrFail({ where: { id } });
    } catch (error) {
      this.logger.error(`Cat with ID ${id} not found`, error.stack);
      throw new NotFoundException(`Cat with ID ${id} not found`);
    }
  }

  async create(createCatDto: CreateCatDto): Promise<Cat> {
    const cat = this.catsRepo.create(createCatDto);
    return this.catsRepo.save(cat);
  }

  async update(id: number, updateCatDto: UpdateCatDto): Promise<Cat> {
    await this.catsRepo.update(id, updateCatDto);
    return this.findOne(id);
  }

  async remove(id: number): Promise<void> {
    const result = await this.catsRepo.delete(id);
    if (result.affected === 0) {
      throw new NotFoundException(`Cat with ID ${id} not found`);
    }
  }
}
```

