### Transform Response with Interceptor in NestJS

Source: https://context7.com/nestjs/nest/llms.txt

Implements a TransformInterceptor that wraps all responses with a standardized format including success status, timestamp, and request path. Uses RxJS map operator to transform the response data before sending to the client.

```typescript
import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

@Injectable()
export class TransformInterceptor<T> implements NestInterceptor<T, any> {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    return next.handle().pipe(
      map(data => ({
        success: true,
        data,
        timestamp: new Date().toISOString(),
        path: context.switchToHttp().getRequest().url,
      })),
    );
  }
}
```

