### Handle Message Patterns in NestJS Microservices

Source: https://context7.com/nestjs/nest/llms.txt

Defines a MathController with message pattern handlers for synchronous and asynchronous RPC-style communication. The @MessagePattern decorator routes incoming messages based on command patterns, while handlers process payloads and return results to clients. Dependencies include @nestjs/microservices and @nestjs/common.

```typescript
import { Controller, Injectable } from '@nestjs/common';
import { MessagePattern, EventPattern, Payload, Ctx, RmqContext } from '@nestjs/microservices';

@Controller()
export class MathController {
  @MessagePattern({ cmd: 'sum' })
  accumulate(@Payload() data: number[]): number {
    return data.reduce((a, b) => a + b, 0);
  }

  @MessagePattern({ cmd: 'multiply' })
  async multiply(@Payload() data: { a: number; b: number }): Promise<number> {
    return data.a * data.b;
  }

  @EventPattern('user_created')
  async handleUserCreated(@Payload() data: any, @Ctx() context: RmqContext) {
    console.log('User created event received:', data);
    const channel = context.getChannelRef();
    const originalMsg = context.getMessage();
    channel.ack(originalMsg);
  }
}
```

